 namespace WPAICG\Core\Stream\Cache; use WP_Error; if (!defined('ABSPATH')) { exit; } require_once __DIR__ . '/methods.php'; class AIPKit_SSE_Message_Cache { public const CACHE_GROUP = 'default'; public const DB_TABLE_SUFFIX = 'aipkit_sse_message_cache'; public const EXPIRY_SECONDS = 60; public const CLEANUP_CRON_HOOK = 'aipkit_cleanup_sse_cache'; private $use_object_cache; private $db_table_name; public function __construct() { global $wpdb; $this->use_object_cache = wp_using_ext_object_cache(); $this->db_table_name = $wpdb->prefix . self::DB_TABLE_SUFFIX; } public function is_using_object_cache(): bool { return is_using_object_cache_logic($this); } public function generate_key_public_wrapper(): string { return generate_key_logic(); } public function set(string $message): string|WP_Error { return set_logic($this, $message); } public function get(string $key): string|WP_Error { return get_logic($this, $key); } public function delete(string $key): bool { return delete_logic($this, $key); } public static function schedule_cleanup_event() { schedule_cleanup_event_logic(self::CLEANUP_CRON_HOOK); } public static function unschedule_cleanup_event() { unschedule_cleanup_event_logic(self::CLEANUP_CRON_HOOK); } public static function run_db_cleanup_static_wrapper() { run_db_cleanup_logic(); } public function get_use_object_cache_status(): bool { return (bool) $this->use_object_cache; } public function get_db_table_name(): string { return $this->db_table_name; } } add_action(AIPKit_SSE_Message_Cache::CLEANUP_CRON_HOOK, ['WPAICG\Core\Stream\Cache\AIPKit_SSE_Message_Cache', 'run_db_cleanup_static_wrapper']); 